    "nested struct param writes fields via at{N} recursion" in {
        val inner = StructSpec(
            "kyo.example.Timeval",
            "Timeval",
            List(StructField("sec", TypeRef.LongT), StructField("usec", TypeRef.LongT)),
            packed = false
        )
        val outer = StructSpec(
            "kyo.example.Rusage",
            "Rusage",
            List(
                StructField("utime", TypeRef.StructT(inner.fqcn)),
                StructField("stime", TypeRef.StructT(inner.fqcn)),
                StructField("maxrss", TypeRef.LongT)
            ),
            packed = false
        )
        val spec = mkTrait(
            "Rusages",
            "kyo_rusage",
            List(mkMethod(
                "push",
                "push_rusage",
                List(ParamSpec("r", TypeRef.StructT(outer.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(outer, inner)
        )
        val src = NativeEmitter.emit(spec)
        // Outer pointer allocation references the nested-expanded CStruct type.
        assert(src.contains("val rPtr = alloc[CStruct3[CStruct2[CLongLong, CLongLong], CStruct2[CLongLong, CLongLong], CLongLong]](1)"))
        // Inner fields written via at{N} pointer + `(!ptr)._K = ...` per-sub-field
        assert(src.contains("val r_utime_ptr = rPtr.at1"))
        assert(src.contains("(!r_utime_ptr)._1 = r.utime.sec"))
        assert(src.contains("(!r_utime_ptr)._2 = r.utime.usec"))
        assert(src.contains("val r_stime_ptr = rPtr.at2"))
        assert(src.contains("(!r_stime_ptr)._1 = r.stime.sec"))
        assert(src.contains("(!rPtr)._3 = r.maxrss"))
    }

    "nested struct in return position reads via at{N} recursion" in {
        val inner = StructSpec(
            "kyo.example.Timeval",
