        val src = NativeEmitter.emit(spec)
        // Outer read constructs the nested Timeval by recursing into `out.at1`.
        assert(src.contains("kyo.example.Rusage(kyo.example.Timeval((!out.at1)._1, (!out.at1)._2), (!out)._2)"))
    }

    "packed struct uses raw Ptr[Byte] with offset-based access (no @packed annotation)" in {
        val ps = StructSpec(
            "kyo.example.Packed",
            "Packed",
            List(StructField("flag", TypeRef.ByteT), StructField("value", TypeRef.IntT)),
            packed = true
        )
        val spec = mkTrait(
            "PackedTrait",
            "kyo_packed",
            List(mkMethod(
                "send",
                "send_packed",
                List(ParamSpec("p", TypeRef.StructT(ps.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(ps)
        )
        val src = NativeEmitter.emit(spec)
        // Packed struct byte-size constant in companion (1 byte + 4 bytes = 5 bytes packed).
        assert(src.contains("inline val Packed_packedSize = 5"))
        // Alloc uses raw byte allocation with the packed byte size.
        assert(src.contains("val pPtr = alloc[Byte](Packed_packedSize)"))
        // Extern decl uses Ptr[Byte] for packed structs (no CStruct type).
        assert(src.contains("def send_packed(p: Ptr[Byte]): CInt = extern"))
        // Field writes use byte-offset pointer arithmetic.
        assert(src.contains("!(pPtr + 0) = p.flag"))
        assert(src.contains("!(pPtr + 1).asInstanceOf[Ptr[CInt]] = p.value"))
        // No @packed annotation anywhere.
        assert(!src.contains("@packed"))
    }

    "pointer field (Buffer[A]) in return-position struct is wrapped as borrowed Buffer with inferred sibling size" in {
        val iov = StructSpec(
