    "variadic method emits a runtime stub instead of @extern (Scala Native cannot express varargs)" in {
        val spec = mkTrait(
            "VariadicLib",
            "kyo_variadic",
            List(
                mkMethod(
                    "vsum",
                    "kyo_it_sum_varargs",
                    List(ParamSpec("count", TypeRef.IntT)),
                    ReturnShape.Primitive(TypeRef.IntT),
                    hasVarargs = true
                )
            )
        )
        val src = NativeEmitter.emit(spec)
        assert(src.contains("def vsum(count: Int, args: Any*)(using kyo.AllowUnsafe): Int ="))
        assert(src.contains("UnsupportedOperationException"))
        assert(src.contains("Variadic method 'vsum' is not supported on Scala Native."))
        // Varargs method must NOT appear in the extern object.
        val externBlock = src.substring(src.indexOf("@extern"))
        assert(!externBlock.contains("kyo_it_sum_varargs"))
        assert(!externBlock.contains("= extern"))
    }

